package org.jsoup.nodes;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.nodes.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.nodes.steps;

import io.cucumber.java.Before;
import io.cucumber.java.Scenario;
import io.cucumber.java.en.*;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Document.OutputSettings;
import org.jsoup.parser.Parser;

import static org.junit.Assert.*;

public class StepDefs {
    private Document document;
    private String output;

    @Given("a document with the content {string}")
    public void a_document_with_the_content(String content) {
        document = Jsoup.parse("<p>" + content + "</p>");
    }

    @Given("the document output settings are configured with charset {string}")
    public void the_document_output_settings_are_configured_with_charset(String charsetName) {
        OutputSettings outputSettings = document.outputSettings();
        try {
            outputSettings.charset(charsetName);
        } catch (Exception e) {
            // Handle exception if charset is not supported
            throw new RuntimeException("Unsupported charset: " + charsetName, e);
        }
    }

    @Given("the document output settings are configured with escape mode {string}")
    public void the_document_output_settings_are_configured_with_escape_mode(String escapeMode) {
        OutputSettings outputSettings = document.outputSettings();
        if ("xhtml".equalsIgnoreCase(escapeMode)) {
            outputSettings.escapeMode(org.jsoup.nodes.Entities.EscapeMode.xhtml);
        } else if ("html".equalsIgnoreCase(escapeMode)) {
            outputSettings.escapeMode(org.jsoup.nodes.Entities.EscapeMode.base);
        }
    }

    @When("the document is converted to HTML")
    public void the_document_is_converted_to_html() {
        try {
            output = document.html();
        } catch (Exception e) {
            // Use try-catch as required
            throw new RuntimeException("Error converting document to HTML", e);
        }
    }

    @Then("the output should not contain the character {string}")
    public void the_output_should_not_contain_the_character(String character) {
        assertFalse("Output contains the character '" + character + "': " + output, 
                   output.contains(character));
    }

    @Then("the output should contain either {string} or {string}")
    public void the_output_should_contain_either_or(String value1, String value2) {
        boolean containsEither = output.contains(value1) || output.contains(value2);
        assertTrue("Output should contain either '" + value1 + "' or '" + value2 + "', but was: " + output, 
                  containsEither);
    }
}
